// Normalize and deduplicate all properties from all sources
const allItems = items;
const allProperties = [];

for (const item of allItems) {
  const body = item.json;
  const props = body.properties || [];
  allProperties.push(...props);
}

// Deduplicate by address
const seen = new Set();
const deduped = allProperties.filter(p => {
  const key = (p.address || '').toLowerCase().trim();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Normalize fields
const normalized = deduped.map(p => ({
  source:           p.source || 'unknown',
  external_id:      p.external_id || `${p.source}_${Math.random().toString(36).slice(2)}`,
  address:          (p.address || '').trim(),
  neighborhood:     p.neighborhood || 'Dallas',
  zip:              p.zip || null,
  latitude:         p.latitude  ? parseFloat(p.latitude)  : null,
  longitude:        p.longitude ? parseFloat(p.longitude) : null,
  property_type:    p.property_type || 'Office',
  sqft:             p.sqft             ? parseInt(p.sqft)             : null,
  lot_size_sqft:    p.lot_size_sqft    ? parseInt(p.lot_size_sqft)    : null,
  year_built:       p.year_built       ? parseInt(p.year_built)       : null,
  occupancy_status: p.occupancy_status || 'Occupied',
  list_price:       p.list_price       ? parseInt(p.list_price)       : null,
  predicted_value:  p.predicted_value  ? parseInt(p.predicted_value)  : null,
  monthly_rent:     p.monthly_rent     ? parseInt(p.monthly_rent)     : null,
  price_per_sqft:   p.price_per_sqft   ? parseInt(p.price_per_sqft)   : null,
  cap_rate:         p.cap_rate         ? parseFloat(p.cap_rate)        : null,
  days_on_market:   p.days_on_market   ? parseInt(p.days_on_market)   : null,
  tier:             p.tier || 'standard',
  raw_data:         p.raw_data || {},
})).filter(p => p.address && p.latitude && p.longitude);

console.log(`Normalized ${normalized.length} properties from ${allProperties.length} raw`);

return [{ json: { properties: normalized, count: normalized.length } }];

// Batch into chunks of 100 for Supabase upsert
const { properties } = items[0].json;
const CHUNK = 100;
const batches = [];
for (let i = 0; i < properties.length; i += CHUNK) {
  batches.push({ json: { properties: properties.slice(i, i + CHUNK) } });
}
console.log(`Split into ${batches.length} batches`);
return batches;

const results = items.map(i => i.json);
const total = results.reduce((s, r) => s + (r.ingested || 0), 0);
console.log(`Pipeline complete. Total ingested: ${total}`);
return [{ json: { pipeline: 'complete', total_ingested: total, timestamp: new Date().toISOString() } }];
